#include <stdio.h>
#define MOD 1000000007LL

long long modPow(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp & 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp >>= 1;
    }
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long pow3 = modPow(3, N);
        long long add = (N % 2 == 0) ? 3 : MOD - 3;
        long long ans = (pow3 + add) % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

